8	const CHAT_CHANNEL_ID_SET = new Set<string>(CHAT_CHANNEL_ORDER);
9	
10	function toChatChannelMeta(params: {
11	  id: ChatChannelId;
12	  channel: PluginPackageChannel;
13	}): ChatChannelMeta {
14	  const label = params.channel.label?.trim();
15	  if (!label) {
16	    throw new Error(`Missing label for bundled chat channel "${params.id}"`);
17	  }
18	
19	  return {
20	    id: params.id,
21	    label,
22	    selectionLabel: params.channel.selectionLabel?.trim() || label,
23	    docsPath: params.channel.docsPath?.trim() || `/channels/${params.id}`,
24	    docsLabel: params.channel.docsLabel?.trim() || undefined,
25	    blurb: params.channel.blurb?.trim() || "",
26	    ...(params.channel.aliases?.length ? { aliases: params.channel.aliases } : {}),
27	    ...(params.channel.order !== undefined ? { order: params.channel.order } : {}),
28	    ...(params.channel.selectionDocsPrefix !== undefined
29	      ? { selectionDocsPrefix: params.channel.selectionDocsPrefix }
30	      : {}),
31	    ...(params.channel.selectionDocsOmitLabel !== undefined
32	      ? { selectionDocsOmitLabel: params.channel.selectionDocsOmitLabel }
33	      : {}),
34	    ...(params.channel.selectionExtras?.length
35	      ? { selectionExtras: params.channel.selectionExtras }
36	      : {}),
37	    ...(params.channel.detailLabel?.trim()
38	      ? { detailLabel: params.channel.detailLabel.trim() }
39	      : {}),
40	    ...(params.channel.systemImage?.trim()
41	      ? { systemImage: params.channel.systemImage.trim() }
42	      : {}),
43	    ...(params.channel.markdownCapable !== undefined
44	      ? { markdownCapable: params.channel.markdownCapable }
45	      : {}),
46	    ...(params.channel.showConfigured !== undefined
47	      ? { showConfigured: params.channel.showConfigured }
48	      : {}),
49	    ...(params.channel.quickstartAllowFrom !== undefined
50	      ? { quickstartAllowFrom: params.channel.quickstartAllowFrom }
51	      : {}),
52	    ...(params.channel.forceAccountBinding !== undefined
53	      ? { forceAccountBinding: params.channel.forceAccountBinding }
54	      : {}),
55	    ...(params.channel.preferSessionLookupForAnnounceTarget !== undefined
56	      ? {
57	          preferSessionLookupForAnnounceTarget: params.channel.preferSessionLookupForAnnounceTarget,
58	        }
59	      : {}),
60	    ...(params.channel.preferOver?.length ? { preferOver: params.channel.preferOver } : {}),
61	  };
62	}
63	
64	function buildChatChannelMetaById(): Record<ChatChannelId, ChatChannelMeta> {
65	  const entries = new Map<ChatChannelId, ChatChannelMeta>();
66	
67	  for (const entry of listBundledPluginMetadata({
68	    includeChannelConfigs: true,
69	    includeSyntheticChannelConfigs: false,
70	  })) {
71	    const channel =
72	      entry.packageManifest && "channel" in entry.packageManifest
73	        ? entry.packageManifest.channel
74	        : undefined;
75	    if (!channel) {
76	      continue;
77	    }
78	    const rawId = channel?.id?.trim();
79	    if (!rawId || !CHAT_CHANNEL_ID_SET.has(rawId)) {
80	      continue;
81	    }
82	    const id = rawId as ChatChannelId;
83	    entries.set(
84	      id,
85	      toChatChannelMeta({
86	        id,
87	        channel,
88	      }),
89	    );
90	  }
91	
92	  const missingIds = CHAT_CHANNEL_ORDER.filter((id) => !entries.has(id));
93	  if (missingIds.length > 0) {
94	    throw new Error(`Missing bundled chat channel metadata for: ${missingIds.join(", ")}`);
95	  }
96	
97	  return Object.freeze(Object.fromEntries(entries)) as Record<ChatChannelId, ChatChannelMeta>;
98	}
99	
100	const CHAT_CHANNEL_META = buildChatChannelMetaById();
101	
102	export const CHAT_CHANNEL_ALIASES: Record<string, ChatChannelId> = Object.freeze(
103	  Object.fromEntries(
104	    Object.values(CHAT_CHANNEL_META)
105	      .flatMap((meta) =>
106	        (meta.aliases ?? []).map((alias) => [alias.trim().toLowerCase(), meta.id] as const),
107	      )
108	      .filter(([alias]) => alias.length > 0)
109	      .toSorted(([left], [right]) => left.localeCompare(right)),
110	  ),
111	) as Record<string, ChatChannelId>;
112	
113	function normalizeChannelKey(raw?: string | null): string | undefined {
114	  const normalized = raw?.trim().toLowerCase();
115	  return normalized || undefined;
116	}
117	
118	export function listChatChannels(): ChatChannelMeta[] {
119	  return CHAT_CHANNEL_ORDER.map((id) => CHAT_CHANNEL_META[id]);
120	}
121	
122	export function listChatChannelAliases(): string[] {
123	  return Object.keys(CHAT_CHANNEL_ALIASES);
124	}
125	
126	export function getChatChannelMeta(id: ChatChannelId): ChatChannelMeta {
127	  return CHAT_CHANNEL_META[id];
128	}
129	
130	export function normalizeChatChannelId(raw?: string | null): ChatChannelId | null {
131	  const normalized = normalizeChannelKey(raw);
132	  if (!normalized) {
133	    return null;
134	  }
135	  const resolved = CHAT_CHANNEL_ALIASES[normalized] ?? normalized;
136	  return CHAT_CHANNEL_ORDER.includes(resolved) ? resolved : null;
137	}
