import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";

import type { PulseBoardAccount } from "./types.js";

/** Resolved account shape used as the generic parameter for the plugin. */
type ResolvedPulseBoardAccount = PulseBoardAccount & {
  accountId: string;
};

export const pulseBoardPlugin = createChatChannelPlugin<ResolvedPulseBoardAccount>({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Connect to PulseBoard bulletin messaging.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: {
      configPrefixes: ["channels.pulseboard"],
    },
    config: {
      listAccountIds: () => [],
      resolveAccount: (_cfg, accountId) => ({
        accountId: accountId ?? "default",
        boardUrl: "",
        apiToken: "",
        username: "",
      }),
      isConfigured: () => false,
    },
    setup: {
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[pulseboard] connected to board for account ${ctx.account.accountId}`,
        );
        return {
          stop: () => {
            ctx.log?.info(
              `[pulseboard] disconnected account ${ctx.account.accountId}`,
            );
          },
        };
      },
    },
    messaging: {
      normalizeTarget: (raw) => raw.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

